class Solution:
    def maxStability(self, n: int, edges: List[List[int]], k: int) -> int:
        graph = [[] for _ in range(n)]
        for u, v, s, must in edges:
            graph[u].append((v, s, must))
            graph[v].append((u, s, must))
        parent = [-1] * n
        rank = [0] * n
        def find(x):
            if parent[x] != -1:
                parent[x] = find(parent[x])
            return parent[x]
        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                if rank[root_x] > rank[root_y]:
                    parent[root_y] = root_x
                else:
                    parent[root_x] = root_y
                    if rank[root_x] == rank[root_y]:
                        rank[root_y] += 1
        upgrades = 0
        for u, v, s, must in edges:
            if must == 0:
                if find(u) != find(v):
                    union(u, v)
                else:
                    upgrades += 1
        if upgrades > n - 1:
            return -1
        max_stability = float('inf')
        for u, v, s, must in edges:
            if must == 0:
                max_stability = min(max_stability, s)
        return max_stability
